package com.socialblog.notification.repository;import com.socialblog.notification.domain.Notification;import org.springframework.data.domain.*;import org.springframework.data.jpa.repository.*;import org.springframework.data.repository.query.Param;import java.time.Instant;import java.util.*;public interface NotificationRepository extends JpaRepository<Notification,UUID>{Page<Notification>findByRecipientIdOrderByCreatedAtDesc(UUID recipient,Pageable p);long countByRecipientIdAndReadAtIsNull(UUID recipient);Optional<Notification>findByIdAndRecipientId(UUID id,UUID recipient);@Modifying @Query("update Notification n set n.readAt=:now where n.recipientId=:recipient and n.readAt is null")int markAllRead(@Param("recipient")UUID recipient,@Param("now")Instant now);}
